example_bad:
fn main() {
    let x = if true {
        42        // i32
    } else {
        "hello"   // &str — Error: incompatible types
    };
}

fixes.code:
let x = if true {
    42
} else {
    0  // Both branches return i32
};

enum Value {
    Number(i32),
    Text(String),
}

let x = if true {
    Value::Number(42)
} else {
    Value::Text("hello".into())
};

let x: Box<dyn std::fmt::Display> = if true {
    Box::new(42)
} else {
    Box::new("hello")
};
